# 爬取图片
def fetch_image(object_html,max_retries=8):
    headers={"User-Agent": ua.random, "Cookie": cookies, "Referer": "https://music.163.com/"}
    for attempt in range(max_retries):
        try:
            response=requests.get(object_html, params={}, headers=headers)
            response.encoding="UTF-8"
            return response.content
        except Exception as e:
            print("[重试 %d/%d] %s -> %s" %(attempt+1, max_retries, object_html[:60], e))
            time.sleep(random.uniform(5,10))
